import{_ as i,o as a,c as p,a0 as e}from"./chunks/framework.Dx25mwie.js";const c=JSON.parse('{"title":"Go-Spring 实战第 7 课 —— Profile 多环境配置：基础配置与环境差异如何避免复制","description":"","frontmatter":{},"headers":[],"relativePath":"docs/8.wechat-series/07-configuration-profile.md","filePath":"docs/8.wechat-series/07-configuration-profile.md"}'),n={name:"docs/8.wechat-series/07-configuration-profile.md"};function t(l,s,h,o,d,r){return a(),p("div",null,[...s[0]||(s[0]=[e(`<h1 id="go-spring-实战第-7-课-——-profile-多环境配置-基础配置与环境差异如何避免复制" tabindex="-1">Go-Spring 实战第 7 课 —— Profile 多环境配置：基础配置与环境差异如何避免复制 <a class="header-anchor" href="#go-spring-实战第-7-课-——-profile-多环境配置-基础配置与环境差异如何避免复制" aria-label="Permalink to &quot;Go-Spring 实战第 7 课 —— Profile 多环境配置：基础配置与环境差异如何避免复制&quot;">​</a></h1><p>上一篇咱们讲了配置优先级和合并语义。然后我们知道，命令行参数、环境变量、Profile 配置、基础配置和默认值都可以进入同一个 <code>path</code> 空间，并且 Go-Spring 会按照确定的规则得到最终配置。</p><p>然而，真实项目里还有一个更具体的问题：配置文件本身应该怎样组织。通常来说，开发、测试、生产等不同环境往往只存在少量差异，比如数据库地址、外部服务超时时间、日志级别和能力开关等，大部分内容都是一样的。如果我们为每个环境都复制一整份配置，那么一旦公共字段需要调整，就要在多份文件里同步完成修改，这样就会带来维护成本。</p><p>Go-Spring 提供了 Profile 机制来解决这个问题。Go-Spring 会首先加载基础配置，然后按照当前激活的 Profile 加载和叠加差异配置。这样，我们就可以把公共配置写在基础文件里，把环境差异写在 Profile 文件里。</p><h2 id="基础配置和-profile-配置" tabindex="-1">基础配置和 Profile 配置 <a class="header-anchor" href="#基础配置和-profile-配置" aria-label="Permalink to &quot;基础配置和 Profile 配置&quot;">​</a></h2><p>Go-Spring 将配置文件分成两类。一类是基础配置，文件名是 <code>app.*</code>，所有环境都会加载它。另一类是 Profile 配置，文件名是 <code>app-{profile}.*</code>，只有对应 Profile 被激活时才会加载。</p><blockquote><p><code>*</code> 表示任意文件类型，比如 YAML、JSON 等。 <code>{profile}</code> 表示当前激活的 Profile 名称，比如 <code>prod</code>、<code>dev</code> 等。</p></blockquote><p>如果我们规定在项目中只能使用 YAML 配置文件，那么项目的配置目录通常可以这样组织:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>conf/</span></span>
<span class="line"><span>  app.yaml        # 基础配置</span></span>
<span class="line"><span>  app-dev.yaml    # 开发环境配置</span></span>
<span class="line"><span>  app-test.yaml   # 测试环境配置</span></span>
<span class="line"><span>  app-prod.yaml   # 生产环境配置</span></span></code></pre></div><p>当我们了解了 Go-Spring 的 Profile 机制以后，再看到上面的配置目录时，就会知道 <code>app.yaml</code> 是基础配置，其他的 <code>app-{profile}.yaml</code> 都是 Profile 配置。</p><p>假设我们有个项目，<code>app.yaml</code> 给出服务端口、默认超时时间和日志级别等公共配置：</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 基础配置</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">server</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  port</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8080</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  timeout</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">5s</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">logging</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  level</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">info</span></span></code></pre></div><p><code>app-prod.yaml</code> 给出生产环境的超时时间和日志级别等差异配置：</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 生产环境配置</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">server</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  timeout</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">3s</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">logging</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  level</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">warn</span></span></code></pre></div><p>当我们激活 <code>prod</code> Profile 后，根据 Go-Spring 的合并语义——叶子值按来源优先级覆盖，对象和 Map 按子 key 合并，Slice 按整体替换处理，最终会得到这样的配置：</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 生产环境的最终配置</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">server</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  port</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8080</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  timeout</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">3s</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">logging</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  level</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">warn</span></span></code></pre></div><p>当然，上面的结果只展示了基础配置和 Profile 配置合并后的状态。如果同一个 key 同时出现在环境变量或命令行参数中，最终仍会被优先级更高的环境变量或命令行参数覆盖。也就是说，Profile 配置高于基础配置，但不是最高优先级。</p><h2 id="spring-profiles-active" tabindex="-1">spring.profiles.active <a class="header-anchor" href="#spring-profiles-active" aria-label="Permalink to &quot;spring.profiles.active&quot;">​</a></h2><p>在 Go-Spring 中，Profile 需要被显式激活。Go-Spring 使用 <code>spring.profiles.active</code> 配置 key 决定本次启动要激活哪些 Profile。</p><p><code>spring.profiles.active</code> 可以是一个逗号分隔的字符串，每一项都是一个 Profile 名称，例如 <code>local</code>、<code>dev</code>、<code>test</code>、<code>prod</code> 等。根据 Go-Spring 的配置加载顺序，我们推荐通过命令行参数或环境变量来设置它，因为这两类来源都会在基础配置之前加载。</p><p>比如，我们可以通过命令行参数激活 <code>prod</code> Profile：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./app</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -Dspring.profiles.active=prod</span></span></code></pre></div><p>也可以通过环境变量激活 <code>prod</code> Profile：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> GS_SPRING_PROFILES_ACTIVE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">prod</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./app</span></span></code></pre></div><p>如果项目确实存在多个配置维度，也可以同时激活多个 Profile。例如，<code>prod</code> 表示生产环境，<code>region-cn</code> 表示中国区域的部署差异：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./app</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -Dspring.profiles.active=prod,region-cn</span></span></code></pre></div><p>对于多个 Profile，Go-Spring 会按照声明顺序进行加载，后加载的 Profile 可以覆盖先加载 Profile 中的同名 key。因此，<code>prod,region-cn</code> 表示先叠加 <code>prod</code> Profile 的差异，再叠加 <code>region-cn</code> Profile 的差异。</p><h2 id="profile-维度" tabindex="-1">Profile 维度 <a class="header-anchor" href="#profile-维度" aria-label="Permalink to &quot;Profile 维度&quot;">​</a></h2><p>通常，Profile 的名称最好来自部署环境，而不是某段具体业务逻辑。对初学者来说，先用 Profile 区分本地、开发、测试、预发、生产这类运行环境，基本就够用了。</p><p>常见的 Profile 名称如下：</p><table tabindex="0"><thead><tr><th>Profile</th><th>维度</th><th>含义</th></tr></thead><tbody><tr><td><code>local</code></td><td>部署环境</td><td>表达本地运行时的配置差异</td></tr><tr><td><code>dev</code></td><td>部署环境</td><td>表达开发环境的配置差异</td></tr><tr><td><code>test</code></td><td>部署环境</td><td>表达测试环境的配置差异</td></tr><tr><td><code>pre</code> 或 <code>staging</code></td><td>部署环境</td><td>表达预发环境的配置差异</td></tr><tr><td><code>prod</code></td><td>部署环境</td><td>表达生产环境的配置差异</td></tr></tbody></table><p>这些 Profile 的含义都很直接：同一个应用部署到不同环境时，数据库地址、日志级别、外部服务地址、超时时间等配置可能不同，于是就把这些差异放到对应的 Profile 配置文件里。</p><p>虽然 Go-Spring 支持同时激活多个 Profile，但在入门阶段没有必要一开始就设计很多维度。Profile 数量越多，叠加顺序和覆盖关系就越难理解。先把部署环境这一条主线设计清楚，通常已经可以覆盖大多数多环境配置场景。</p><h2 id="spring-app-config-dir" tabindex="-1">spring.app.config.dir <a class="header-anchor" href="#spring-app-config-dir" aria-label="Permalink to &quot;spring.app.config.dir&quot;">​</a></h2><p>Go-Spring 默认的配置目录是 <code>./conf</code>。如果项目需要将配置文件放到其他目录，可以通过 <code>spring.app.config.dir</code> 配置 key 来修改。这里同样推荐使用环境变量或命令行参数来指定。</p><p>比如，我们可以通过环境变量来指定配置目录：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> GS_SPRING_APP_CONFIG_DIR</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">./config</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./app</span></span></code></pre></div><p>也可以通过命令行参数来指定配置目录：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./myapp</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -Dspring.app.config.dir=./config</span></span></code></pre></div><p><code>spring.app.config.dir</code> 和 <code>spring.profiles.active</code> 有些不同。通常来说，它的值在所有环境中应当保持一致，只是不同项目可能采用不同的配置目录。因此，我们也可以在代码中为项目设置它的值。</p><p>我们可以通过下面的代码来指定配置目录：</p><div class="language-go vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">gs.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Configure</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">func</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">app</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> gs</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">App</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  app.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Property</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;spring.app.config.dir&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;./config&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}).</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Run</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">()</span></span></code></pre></div><h2 id="profile-多环境配置" tabindex="-1">Profile 多环境配置 <a class="header-anchor" href="#profile-多环境配置" aria-label="Permalink to &quot;Profile 多环境配置&quot;">​</a></h2><p>Profile 多环境配置的意义是把“公共配置”和“环境差异”分开放置。基础配置负责表达所有环境共享的部分，Profile 配置负责表达当前环境或能力维度的差异。当需要使用多个 Profile 时，按照声明顺序依次叠加就可以了。</p><p>这样组织之后，配置结构更清晰，修改公共字段时也更不容易遗漏。</p>`,45)])])}const g=i(n,[["render",t]]);export{c as __pageData,g as default};
